import pandas as pd
import matplotlib.pyplot as plt

# load the output generated by the C++ program
# assumes working directory is the repo root

def main():
    df = pd.read_csv("regret.csv")
    plt.figure(figsize=(8, 4))
    plt.plot(df.t, df.unpooled, label="Unpooled Thompson")
    plt.plot(df.t, df.pooled,  label="Pooled Thompson")
    plt.xlabel("t")
    plt.ylabel("Avg. cumulative regret")
    plt.legend()
    plt.title("Comparison of C++ simulation results")
    plt.tight_layout()
    plt.show()

if __name__ == "__main__":
    main()
